import React from 'react';

const App: React.FC = () =>
	React.createElement('div', { style: { fontFamily: 'sans-serif', padding: '1rem' } }, [
		React.createElement('h1', { key: 'title' }, 'ISP Admin Web'),
		React.createElement(
			'p',
			{ key: 'subtitle' },
			'Painel administrativo inicial funcionando. Próximo passo: montar as telas completas e integrar com o backend.',
		),
	]);

export default App;
